9359 /// Return true if "icmp Pred LHS RHS" is always true.
9360 static bool isTruePredicate(CmpInst::Predicate Pred, const Value *LHS,
9361                             const Value *RHS) {
9362   if (ICmpInst::isTrueWhenEqual(Pred) && LHS == RHS)
9363     return true;
9364 
9365   switch (Pred) {
9366   default:
9367     return false;
9368 
9369   case CmpInst::ICMP_SLE: {
9370     const APInt *C;
9371 
9372     // LHS s<= LHS +_{nsw} C   if C >= 0
9373     // LHS s<= LHS | C         if C >= 0
9374     if (match(RHS, m_NSWAdd(m_Specific(LHS), m_APInt(C))) ||
9375         match(RHS, m_Or(m_Specific(LHS), m_APInt(C))))
9376       return !C->isNegative();
9377 
9378     // LHS s<= smax(LHS, V) for any V
9379     if (match(RHS, m_c_SMax(m_Specific(LHS), m_Value())))
9380       return true;
9381 
9382     // smin(RHS, V) s<= RHS for any V
9383     if (match(LHS, m_c_SMin(m_Specific(RHS), m_Value())))
9384       return true;
9385 
9386     // Match A to (X +_{nsw} CA) and B to (X +_{nsw} CB)
9387     const Value *X;
9388     const APInt *CLHS, *CRHS;
9389     if (match(LHS, m_NSWAddLike(m_Value(X), m_APInt(CLHS))) &&
9390         match(RHS, m_NSWAddLike(m_Specific(X), m_APInt(CRHS))))
9391       return CLHS->sle(*CRHS);
9392 
9393     return false;
9394   }
9395 
9396   case CmpInst::ICMP_ULE: {
9397     // LHS u<= LHS +_{nuw} V for any V
9398     if (match(RHS, m_c_Add(m_Specific(LHS), m_Value())) &&
9399         cast<OverflowingBinaryOperator>(RHS)->hasNoUnsignedWrap())
9400       return true;
9401 
9402     // LHS u<= LHS | V for any V
9403     if (match(RHS, m_c_Or(m_Specific(LHS), m_Value())))
9404       return true;
9405 
9406     // LHS u<= umax(LHS, V) for any V
9407     if (match(RHS, m_c_UMax(m_Specific(LHS), m_Value())))
9408       return true;
9409 
9410     // RHS >> V u<= RHS for any V
9411     if (match(LHS, m_LShr(m_Specific(RHS), m_Value())))
