9478 /// Return true if "icmp LPred X, LCR" implies "icmp RPred X, RCR" is true.
9479 /// Return false if "icmp LPred X, LCR" implies "icmp RPred X, RCR" is false.
9480 /// Otherwise, return std::nullopt if we can't infer anything.
9481 static std::optional<bool>
9482 isImpliedCondCommonOperandWithCR(CmpPredicate LPred, const ConstantRange &LCR,
9483                                  CmpPredicate RPred, const ConstantRange &RCR) {
9484   auto CRImpliesPred = [&](ConstantRange CR,
9485                            CmpInst::Predicate Pred) -> std::optional<bool> {
9486     // If all true values for lhs and true for rhs, lhs implies rhs
9487     if (CR.icmp(Pred, RCR))
9488       return true;
9489 
9490     // If there is no overlap, lhs implies not rhs
9491     if (CR.icmp(CmpInst::getInversePredicate(Pred), RCR))
9492       return false;
9493 
9494     return std::nullopt;
9495   };
9496   if (auto Res = CRImpliesPred(ConstantRange::makeAllowedICmpRegion(LPred, LCR),
9497                                RPred))
9498     return Res;
9499   if (LPred.hasSameSign() ^ RPred.hasSameSign()) {
9500     LPred = LPred.hasSameSign() ? ICmpInst::getFlippedSignednessPredicate(LPred)
9501                                 : LPred.dropSameSign();
9502     RPred = RPred.hasSameSign() ? ICmpInst::getFlippedSignednessPredicate(RPred)
9503                                 : RPred.dropSameSign();
9504     return CRImpliesPred(ConstantRange::makeAllowedICmpRegion(LPred, LCR),
9505                          RPred);
9506   }
9507   return std::nullopt;
9508 }
